module RefModule(
  input [7:0] data,
  output reg parity_bit
);integer obf_i;
  reg [7:0] temp_data;
  reg [3:0] count;

  always @* begin
    temp_data = data;
    count = 0;
    for(obf_i=0; obf_i<8; obf_i=obf_i+1) begin
      count = count + temp_data[obf_i];
    end
    if(count % 2 == 1) begin
      parity_bit = 1;
    end
    else begin
      parity_bit = 0;
    end
  end

endmodule
